function applyTransform() {
  document.getElementById('graph-root').setAttribute(
    'transform', `translate(${transform.x},${transform.y}) scale(${transform.scale})`
  );
}

function fitView() {
  if (!nodes.length) return;
  const canvasEl = document.getElementById('canvas-area');
  const W = canvasEl.clientWidth, H = canvasEl.clientHeight;
  const minX = Math.min(...nodes.map(n => n._x));
  const maxX = Math.max(...nodes.map(n => n._x + n._w));
  const minY = Math.min(...nodes.map(n => n._y));
  const maxY = Math.max(...nodes.map(n => n._y + n._h));
  const gW = maxX - minX + 80, gH = maxY - minY + 80;
  const scale = Math.min(W / gW, H / gH, 1.2);
  transform.scale = scale;
  transform.x = (W - gW * scale) / 2 - minX * scale + 40;
  transform.y = (H - gH * scale) / 2 - minY * scale + 40;
  applyTransform();
}

function zoomIn() { transform.scale = Math.min(transform.scale * 1.2, 3); applyTransform(); }
function zoomOut() { transform.scale = Math.max(transform.scale / 1.2, 0.2); applyTransform(); }

function setupPan() {
  const area = document.getElementById('canvas-area');
  area.addEventListener('mousedown', e => {
    if (e.target.closest('.node-group')) return;
    dragging = true;
    dragStart = { x: e.clientX - transform.x, y: e.clientY - transform.y };
    area.classList.add('dragging');
  });
  window.addEventListener('mousemove', e => {
    if (!dragging) return;
    transform.x = e.clientX - dragStart.x;
